const item = $input.first();
const from = item.json.from || '';
const subject = item.json.subject || '';
const text = item.json.text || item.json.textHtml || '';

// HTMLタグを除去
const cleanText = text.replace(/<[^>]*>/g, '').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').trim();

return [
  {
    json: {
      from,
      subject,
      body: cleanText
    }
  }
];

// カレンダーイベントを整形
const events = $input.all();
const emailData = $('メール内容を整形').first().json;

const formattedEvents = events.map(e => {
  const ev = e.json;
  const start = ev.start?.dateTime || ev.start?.date || '';
  const end = ev.end?.dateTime || ev.end?.date || '';
  const title = ev.summary || '(無題)';
  return { title, start, end };
});

// 今日の日付を取得
const today = new Date();
const todayStr = today.toLocaleDateString('ja-JP', {
  year: 'numeric', month: 'long', day: 'numeric', weekday: 'long'
});

// Claudeへのプロンプトを組み立てる
const calendarSummary = formattedEvents.length > 0
  ? formattedEvents.map(e => {
      const start = new Date(e.start).toLocaleString('ja-JP', {month: 'long', day: 'numeric', weekday: 'short', hour: '2-digit', minute: '2-digit'});
      const end = new Date(e.end).toLocaleString('ja-JP', {hour: '2-digit', minute: '2-digit'});
      return `・${start}〜${end} ${e.title}`;
    }).join('\n')
  : '（予定なし）';

const prompt = `以下のメールを読み、希望日時を確認してGoogleカレンダーの空き状況を考慮した返信文を日本語で作成してください。

【今日の日付】
${todayStr}

【受信メール】
送信者: ${emailData.from}
件名: ${emailData.subject}
本文:
${emailData.body}

【今後30日間のGoogleカレンダー予定】
${calendarSummary}

---
【指示】
1. メール本文から相手の希望日時候補をすべて読み取ってください。
2. カレンダーの予定と照合して、空いている日時を特定してください。
3. 空いている日時を明示しながら、丁寧な返信文を作成してください。
4. もし希望日時がすべて埋まっている場合は、代替案を提示してください。
5. 件名は「Re: 元の件名」形式にしてください。

出力形式:
件名: Re: [件名]

[返信本文]`;

return [
  {
    json: {
      prompt,
      emailFrom: emailData.from,
      emailSubject: emailData.subject,
      emailBody: emailData.body,
      calendarEvents: formattedEvents
    }
  }
];

const claudeResponse = $input.first().json;
const prevData = $('カレンダー情報 & プロンプト作成').first().json;

// Claudeの返信テキストを取得
const replyText = claudeResponse.content?.[0]?.text || '';

// カレンダーイベント件数
const eventCount = prevData.calendarEvents?.length || 0;

const message = `📧 新着メールへの返信案

【元メール】
送信者: ${prevData.emailFrom}
件名: ${prevData.emailSubject}

【Claudeが作成した返信案】
（カレンダー ${eventCount}件の予定を確認済み）

${replyText}

---
この返信内容でよろしいですか？
✅ 承認して送信 / ✏️ 修正が必要`;

return [
  {
    json: {
      lineMessage: message,
      emailFrom: prevData.emailFrom,
      emailSubject: prevData.emailSubject,
      replyDraft: replyText
    }
  }
];
